    if match:
        N = int(match.group('N'))
        M = int(match.group('M'))
        if 'apples' in line:
            return N + M
        elif 'candies' in line:
            return N - M if M <= N else 'INVALID'
        elif 'marbles' in line:
            return N - M if M <= N else 'INVALID'
    return 'INVALID'

